    long long r_max = std::numeric_limits<long long>::min();

    for (int i = N - 1; i >= 0; --i) {
        // Check if nums[i] is strictly greater than the maximum encountered so far from the right
        R[i] = (nums[i] > r_max);
        // Update the maximum encountered so far
        r_max = std::max(r_max, nums[i]);
    }

    // Collect results: an element is effective if L[i] OR R[i] is true.
    std::vector<long long> result;
    for (int i = 0; i < N; ++i) {
        if (L[i] || R[i]) {
            result.push_back(nums[i]);
        }
    }

    return result;
}

